mapper.select:
SELECT dr.*, u.display_name as userName, u.avatar_url as userAvatar, mi.name as itemName, mi.price as itemPrice, mi.image_url as itemImage, dri.id as img_id, dri.dish_review_id as img_dish_review_id, dri.image_url as img_image_url, dri.sort_order as img_sort_order, dri.created_at as img_created_at, dri.updated_at as img_updated_at FROM dish_reviews dr LEFT JOIN users u ON dr.user_id = u.id LEFT JOIN menu_items mi ON dr.menu_item_id = mi.id LEFT JOIN dish_review_images dri ON dr.id = dri.dish_review_id WHERE dr.restaurant_id = #{restaurantId}
AND dr.menu_item_id = #{menuItemId}
AND dr.rating = #{rating}
ORDER BY dr.created_at DESC, dri.sort_order ASC
